use std::path::{Path, PathBuf};
use std::time::{SystemTime, UNIX_EPOCH};

pub struct NativeOperationAdapter;

impl NativeOperationAdapter {
    pub fn invoke(
        operation: &str,
        tool_name: &str,
        args: &Map<String, Value>,
        context: &WorkspaceContext,
        dry_run: bool,
        mutating: bool,
    ) -> Result<AdapterOutcome, String> {
        if dry_run {
            return Ok(AdapterOutcome {
                ok: true,
                summary: format!("dry run: {tool_name} would execute native XML/DSL operation"),
                changes: if mutating {
                    vec!["no files changed because dryRun is true".to_string()]
                } else {
                    Vec::new()
                },
                warnings: Vec::new(),
                errors: Vec::new(),
                artifacts: Vec::new(),
                stdout: None,
                stderr: None,
                command: None,
            });
        }

        if mutating {
            return Ok(handle_mutation(
                operation, tool_name, args, context, dry_run,
            ));
        }

        if operation == "role-info" {
            return Ok(analyze_role_info(args, context));
        }
        if operation == "role-validate" {
            return Ok(validate_role(args, context));
        }
        if operation == "subsystem-info" {
            return Ok(analyze_subsystem_info(args, context));
        }
        if operation == "subsystem-validate" {
            return Ok(validate_subsystem(args, context));
        }
        if operation == "interface-validate" {
            return Ok(validate_interface(args, context));
        }
        if operation == "cf-validate" {
            return Ok(validate_cf(args, context));
        }
        if operation == "cfe-validate" {
            return Ok(validate_cfe(args, context));
        }
        if operation == "cfe-diff" {
            return Ok(diff_cfe(args, context));
        }
        if operation == "cf-info" {
            return Ok(analyze_cf_info(args, context));
        }
        if operation == "meta-info" {
            return Ok(analyze_meta_info(args, context));
        }
        if operation == "meta-validate" {
            return Ok(validate_meta(args, context));
        }
        if operation == "mxl-info" {
            return Ok(analyze_mxl_info(args, context));
        }
        if operation == "mxl-validate" {
            return Ok(validate_mxl(args, context));
        }
        if operation == "mxl-decompile" {
            return Ok(decompile_mxl(args, context));
        }
        if operation == "skd-info" {
            return Ok(analyze_skd_info(args, context));
        }
        if operation == "skd-validate" {
            return Ok(validate_skd(args, context));
        }
        if operation == "form-info" {
            return Ok(analyze_form_info(args, context));
        }
        if operation == "form-validate" {
            return Ok(validate_form(args, context));
        }

        let target = resolve_target(operation, args, context)?;
        let text = fs::read_to_string(&target)
            .map_err(|err| format!("failed to read {}: {err}", target.display()))?;
        let report = analyze_xml(operation, tool_name, &target, &text);
        Ok(report)
    }
}

fn handle_mutation(
    operation: &str,
    tool_name: &str,
    args: &Map<String, Value>,
    context: &WorkspaceContext,
    dry_run: bool,
) -> AdapterOutcome {
    if dry_run {
        return AdapterOutcome {
            ok: true,
            summary: format!("dry run: {tool_name} would execute native XML/DSL operation"),
            changes: vec!["no files changed because dryRun is true".to_string()],
            warnings: Vec::new(),
            errors: Vec::new(),
            artifacts: Vec::new(),
            stdout: None,
            stderr: None,
            command: None,
        };
    }

    match operation {
        "cf-init" => create_configuration_scaffold(args, context),
        "cf-edit" => edit_cf(args, context),
        "cfe-borrow" => borrow_cfe(args, context),
        "cfe-init" => create_extension_scaffold(args, context),
        "cfe-patch-method" => patch_extension_method(args, context),
        "meta-compile" => compile_meta(args, context),
        "meta-edit" => edit_meta(args, context),
        "subsystem-compile" => compile_subsystem(args, context),
        "meta-remove" => remove_metadata_object(args, context),
        "form-remove" => remove_form(args, context),
        "template-add" => add_template(args, context),
        "template-remove" => remove_template(args, context),
        "form-add" => add_form(args, context),
        "form-compile" => compile_form(args, context),
        "form-edit" => edit_form(args, context),
        "mxl-compile" => compile_mxl(args, context),
        "skd-compile" => compile_skd(args, context),
        "skd-edit" => edit_skd(args, context),
        "role-compile" => compile_role(args, context),
        "interface-edit" => edit_interface(args, context),
        "subsystem-edit" => edit_subsystem(args, context),
        _ => AdapterOutcome {
            ok: false,
            summary: format!("{tool_name} is native, but this mutating operation needs a concrete JSON/XML payload before execution"),
            changes: Vec::new(),
            warnings: Vec::new(),
            errors: vec![format!(
                "native handler for {tool_name} refuses to mutate without an implemented operation-specific writer"
            )],
            artifacts: Vec::new(),
            stdout: None,
            stderr: None,
            command: None,
        },
    }
}

