fn analyze_form_info(args: &Map<String, Value>, context: &WorkspaceContext) -> AdapterOutcome {
    let result = (|| -> Result<(String, PathBuf), String> {
        let raw_path = required_path(args, &["formPath", "FormPath", "path", "Path"], "FormPath")?;
        let form_path = resolve_form_info_path(absolutize(raw_path, &context.cwd));
        if !form_path.is_file() {
            return Err(format!("File not found: {}", form_path.display()));
        }

        let limit = int_arg(args, &["limit", "Limit"])
            .and_then(|value| usize::try_from(value).ok())
            .unwrap_or(150);
        let offset = int_arg(args, &["offset", "Offset"])
            .and_then(|value| usize::try_from(value).ok())
            .unwrap_or(0);
        let expand = string_arg(args, &["expand", "Expand"]).unwrap_or("");

        let text = read_utf8_sig(&form_path)?;
        let doc = Document::parse(text.trim_start_matches('\u{feff}'))
            .map_err(|err| format!("XML parse error in {}: {err}", form_path.display()))?;
        let root = doc.root_element();
        let is_extension = form_child(root, "BaseForm").is_some();
        let (form_name, object_context) = form_info_context(&form_path);

        let mut lines = Vec::new();
        let form_title = form_child(root, "Title")
            .map(form_ml_text)
            .filter(|value| !value.is_empty());
        let ext_marker = if is_extension { " [EXTENSION]" } else { "" };
        let mut header = format!("=== Form: {form_name}{ext_marker}");
        if let Some(title) = form_title {
            header.push_str(&format!(" — \"{title}\""));
        }
        if !object_context.is_empty() {
            header.push_str(&format!(" ({object_context})"));
        }
        header.push_str(" ===");
        lines.push(header);

        let prop_names = [
            "Width",
            "Height",
            "Group",
            "WindowOpeningMode",
            "EnterKeyBehavior",
            "AutoTitle",
            "AutoURL",
            "AutoFillCheck",
            "Customizable",
            "CommandBarLocation",
            "SaveDataInSettings",
            "AutoSaveDataInSettings",
            "AutoTime",
            "UsePostingMode",
            "RepostOnWrite",
            "UseForFoldersAndItems",
            "ReportResult",
            "DetailsData",
            "ReportFormType",
            "VerticalScroll",
            "ScalingMode",
        ];
        let props = prop_names
            .iter()
            .filter_map(|name| {
                form_child(root, name).and_then(|node| {
                    let value = form_ml_text(node);
                    if value.is_empty() {
                        None
                    } else {
                        Some(format!("{name}={value}"))
                    }
                })
            })
            .collect::<Vec<_>>();
        if !props.is_empty() {
            lines.push(String::new());
            lines.push(format!("Properties: {}", props.join(", ")));
        }

        if let Some(events) = form_child(root, "Events") {
            let event_lines = form_event_lines(events);
            if !event_lines.is_empty() {
                lines.push(String::new());
                lines.push("Events:".to_string());
                lines.extend(event_lines);
            }
        }

        let cb_loc = form_child_text(root, "CommandBarLocation")
            .filter(|value| !value.is_empty())
            .unwrap_or_else(|| "Auto".to_string());
        let acb_lines = if cb_loc != "None" {
            form_child(root, "AutoCommandBar")
                .map(form_main_command_bar_lines)
                .unwrap_or_default()
        } else {
            Vec::new()
        };
        if !acb_lines.is_empty() && matches!(cb_loc.as_str(), "Auto" | "Top") {
            lines.push(String::new());
            lines.extend(acb_lines.clone());
        }

        let mut tree_state = FormTreeState {
            has_collapsed: false,
        };
        if let Some(child_items) = form_child(root, "ChildItems") {
            let mut tree_lines = Vec::new();
            form_build_tree(child_items, "  ", &mut tree_lines, expand, &mut tree_state);
            lines.push(String::new());
            lines.push("Elements:".to_string());
            lines.extend(tree_lines);
        }

        if !acb_lines.is_empty() && cb_loc == "Bottom" {
            lines.push(String::new());
            lines.extend(acb_lines);
        }

        if let Some(attrs) = form_child(root, "Attributes") {
            let attr_lines = form_attribute_lines(attrs);
            if !attr_lines.is_empty() {
                lines.push(String::new());
                lines.push("Attributes:".to_string());
                lines.extend(attr_lines);
            }
        }

        if let Some(params) = form_child(root, "Parameters") {
            let param_lines = form_parameter_lines(params);
            if !param_lines.is_empty() {
                lines.push(String::new());
                lines.push("Parameters:".to_string());
                lines.extend(param_lines);
            }
        }

        if let Some(commands) = form_child(root, "Commands") {
            let command_lines = form_command_lines(commands);
            if !command_lines.is_empty() {
                lines.push(String::new());
                lines.push("Commands:".to_string());
                lines.extend(command_lines);
            }
        }

        if is_extension {
            let base_form = form_child(root, "BaseForm").expect("checked above");
            let version = base_form.attribute("version").unwrap_or("");
            let base_form_text = if version.is_empty() {
                "present".to_string()
            } else {
                format!("present (version {version})")
            };
            lines.push(String::new());
            lines.push(format!("BaseForm: {base_form_text}"));
        }

        if tree_state.has_collapsed {
            lines.push(String::new());
            lines.push(
                "Hint: use -Expand <name> to expand a collapsed section, -Expand * for all"
                    .to_string(),
            );
        }

        let total_lines = lines.len();
        if offset > 0 {
            if offset >= total_lines {
                return Ok((
                    format!(
                        "[INFO] Offset {offset} exceeds total lines ({total_lines}). Nothing to show.\n"
                    ),
                    form_path,
                ));
            }
            lines = lines.into_iter().skip(offset).collect();
        }

        let stdout = if lines.len() > limit {
            let shown = lines.iter().take(limit).cloned().collect::<Vec<_>>();
            format!(
                "{}\n\n[TRUNCATED] Shown {limit} of {total_lines} lines. Use -Offset {} to continue.\n",
                shown.join("\n"),
                offset + limit
            )
        } else {
            format!("{}\n", lines.join("\n"))
        };

        Ok((stdout, form_path))
    })();

    match result {
        Ok((stdout, artifact)) => AdapterOutcome {
            ok: true,
            summary: "unica.form.info completed with native form analyzer".to_string(),
            changes: Vec::new(),
            warnings: Vec::new(),
            errors: Vec::new(),
            artifacts: vec![artifact.display().to_string()],
            stdout: Some(stdout),
            stderr: Some(String::new()),
            command: None,
        },
        Err(error) => AdapterOutcome {
            ok: false,
            summary: "unica.form.info failed in native form analyzer".to_string(),
            changes: Vec::new(),
            warnings: Vec::new(),
            errors: vec![error.clone()],
            artifacts: Vec::new(),
            stdout: Some(String::new()),
            stderr: Some(format!("{error}\n")),
            command: None,
        },
    }
}

fn resolve_form_info_path(mut form_path: PathBuf) -> PathBuf {
    if form_path.is_dir() {
        form_path = form_path.join("Ext").join("Form.xml");
    }
    if !form_path.is_file()
        && form_path
            .file_name()
            .and_then(|name| name.to_str())
            .is_some_and(|name| name == "Form.xml")
    {
        let candidate = form_path
            .parent()
            .unwrap_or_else(|| Path::new(""))
            .join("Ext")
            .join("Form.xml");
        if candidate.is_file() {
            form_path = candidate;
        }
    }
    if !form_path.is_file()
        && form_path
            .extension()
            .and_then(|ext| ext.to_str())
            .is_some_and(|ext| ext.eq_ignore_ascii_case("xml"))
    {
        let stem = form_path.file_stem().and_then(|stem| stem.to_str());
        if let (Some(stem), Some(parent)) = (stem, form_path.parent()) {
            let candidate = parent.join(stem).join("Ext").join("Form.xml");
            if candidate.is_file() {
                form_path = candidate;
            }
        }
    }
    form_path
}

fn form_info_context(form_path: &Path) -> (String, String) {
    let resolved = form_path
        .canonicalize()
        .unwrap_or_else(|_| form_path.to_path_buf());
    let parts = resolved
        .components()
        .filter_map(|component| match component {
            std::path::Component::Normal(part) => part.to_str().map(ToOwned::to_owned),
            _ => None,
        })
        .collect::<Vec<_>>();
    if let Some(forms_idx) = parts.iter().rposition(|part| part == "Forms") {
        if forms_idx + 1 < parts.len() {
            let form_name = parts[forms_idx + 1].clone();
            let object_context = if forms_idx >= 2 {
                format!("{}.{}", parts[forms_idx - 2], parts[forms_idx - 1])
            } else {
                String::new()
            };
            return (form_name, object_context);
        }
    }
    if let Some(ext_idx) = parts.iter().rposition(|part| part == "Ext") {
        if ext_idx >= 2 {
            return (parts[ext_idx - 1].clone(), parts[ext_idx - 2].clone());
        }
    }
    (
        form_path
            .file_stem()
            .and_then(|stem| stem.to_str())
            .unwrap_or("Form")
            .to_string(),
        String::new(),
    )
}

fn form_child<'a>(
    node: roxmltree::Node<'a, 'a>,
    local_name: &str,
) -> Option<roxmltree::Node<'a, 'a>> {
    node.children()
        .find(|child| child.is_element() && child.tag_name().name() == local_name)
}

fn form_children<'a>(
    node: roxmltree::Node<'a, 'a>,
    local_name: &str,
) -> Vec<roxmltree::Node<'a, 'a>> {
    node.children()
        .filter(|child| child.is_element() && child.tag_name().name() == local_name)
        .collect()
}

fn form_child_text(node: roxmltree::Node<'_, '_>, local_name: &str) -> Option<String> {
    form_child(node, local_name)
        .map(form_ml_text)
        .filter(|value| !value.is_empty())
}

fn form_ml_text(node: roxmltree::Node<'_, '_>) -> String {
    for item in form_children(node, "item") {
        for child in item.children().filter(|child| child.is_element()) {
            if child.tag_name().name() == "content" {
                if let Some(text) = child.text() {
                    if !text.is_empty() {
                        return text.to_string();
                    }
                }
            }
        }
    }
    node.text().unwrap_or("").trim().to_string()
}

fn form_event_lines(events: roxmltree::Node<'_, '_>) -> Vec<String> {
    form_children(events, "Event")
        .into_iter()
        .map(|event| {
            let name = event.attribute("name").unwrap_or("");
            let handler = event.text().unwrap_or("");
            let call_type = event.attribute("callType").unwrap_or("");
            let call_type = if call_type.is_empty() {
                String::new()
            } else {
                format!("[{call_type}]")
            };
            format!("  {name}{call_type} -> {handler}")
        })
        .collect()
}

fn form_main_command_bar_lines(acb: roxmltree::Node<'_, '_>) -> Vec<String> {
    let autofill = form_child_text(acb, "Autofill")
        .map(|value| value != "false")
        .unwrap_or(true);
    let h_align = form_child_text(acb, "HorizontalAlign");
    let mut flags = vec![if autofill { "autofill" } else { "no-autofill" }.to_string()];
    if let Some(align) = h_align {
        flags.push(format!("align={align}"));
    }

    let mut buttons = Vec::new();
    if let Some(child_items) = form_child(acb, "ChildItems") {
        for button in child_items.children().filter(|child| {
            child.is_element() && !form_skip_elements().contains(&child.tag_name().name())
        }) {
            let name = button.attribute("name").unwrap_or("");
            let cmd_ref = form_child_text(button, "CommandName").unwrap_or_default();
            let loc = form_child_text(button, "LocationInCommandBar")
                .map(|value| format!(" [{value}]"))
                .unwrap_or_default();
            let tag = form_element_tag(button);
            if cmd_ref.is_empty() {
                buttons.push(format!("  {tag} {name}{loc}"));
            } else {
                buttons.push(format!("  {tag} {name} -> {cmd_ref}{loc}"));
            }
        }
    }
    if buttons.is_empty() && autofill && flags.len() == 1 {
        return vec!["AutoCommandBar [autofill]".to_string()];
    }
    let mut lines = vec![format!("AutoCommandBar [{}]", flags.join(", "))];
    lines.extend(buttons);
    lines
}

struct FormTreeState {
    has_collapsed: bool,
}

fn form_build_tree(
    child_items: roxmltree::Node<'_, '_>,
    prefix: &str,
    tree_lines: &mut Vec<String>,
    expand: &str,
    state: &mut FormTreeState,
) {
    let children = child_items
        .children()
        .filter(|child| {
            child.is_element() && !form_skip_elements().contains(&child.tag_name().name())
        })
        .collect::<Vec<_>>();

    for (index, child) in children.iter().enumerate() {
        let last = index + 1 == children.len();
        let connector = if last { "└─" } else { "├─" };
        let continuation = if last { "  " } else { "│ " };
        let tag = form_element_tag(*child);
        let name = child.attribute("name").unwrap_or("");
        let flags = form_flags(*child);
        let events = form_events_str(*child);
        let binding = form_binding(*child);
        let title = form_title_differs(*child, name)
            .map(|title| format!(" [title:{title}]"))
            .unwrap_or_default();
        tree_lines.push(format!(
            "{prefix}{connector} {tag} {name}{binding}{flags}{title}{events}"
        ));

        match child.tag_name().name() {
            "Page" => {
                let child_items = form_child(*child, "ChildItems");
                let page_name = child.attribute("name").unwrap_or("");
                let page_title = form_title_differs(*child, page_name);
                let should_expand = expand == "*"
                    || expand == page_name
                    || page_title.as_deref().is_some_and(|title| expand == title);
                if should_expand {
                    if let Some(child_items) = child_items {
                        form_build_tree(
                            child_items,
                            &format!("{prefix}{continuation}"),
                            tree_lines,
                            expand,
                            state,
                        );
                    }
                } else {
                    let count = child_items
                        .map(form_count_significant_children)
                        .unwrap_or(0);
                    if let Some(line) = tree_lines.last_mut() {
                        line.push_str(&format!(" ({count} items)"));
                    }
                    state.has_collapsed = true;
                }
            }
            "UsualGroup" | "Pages" | "Table" | "CommandBar" | "ButtonGroup" | "Popup" => {
                if let Some(child_items) = form_child(*child, "ChildItems") {
                    form_build_tree(
                        child_items,
                        &format!("{prefix}{continuation}"),
                        tree_lines,
                        expand,
                        state,
                    );
                }
            }
            _ => {}
        }
    }
}

fn form_skip_elements() -> &'static [&'static str] {
    &[
        "ExtendedTooltip",
        "ContextMenu",
        "AutoCommandBar",
        "SearchStringAddition",
        "ViewStatusAddition",
        "SearchControlAddition",
        "ColumnGroup",
    ]
}

fn form_element_tag(node: roxmltree::Node<'_, '_>) -> String {
    match node.tag_name().name() {
        "UsualGroup" => {
            let orient = match form_child_text(node, "Group").as_deref() {
                Some("Vertical") => ":V",
                Some("Horizontal") => ":H",
                Some("AlwaysHorizontal") => ":AH",
                Some("AlwaysVertical") => ":AV",
                _ => "",
            };
            let collapse = if form_child_text(node, "Behavior").as_deref() == Some("Collapsible") {
                ",collapse"
            } else {
                ""
            };
            format!("[Group{orient}{collapse}]")
        }
        "InputField" => "[Input]".to_string(),
        "CheckBoxField" => "[Check]".to_string(),
        "LabelDecoration" => "[Label]".to_string(),
        "LabelField" => "[LabelField]".to_string(),
        "PictureDecoration" => "[Picture]".to_string(),
        "PictureField" => "[PicField]".to_string(),
        "CalendarField" => "[Calendar]".to_string(),
        "Table" => "[Table]".to_string(),
        "Button" => "[Button]".to_string(),
        "CommandBar" => "[CmdBar]".to_string(),
        "Pages" => "[Pages]".to_string(),
        "Page" => "[Page]".to_string(),
        "Popup" => "[Popup]".to_string(),
        "ButtonGroup" => "[BtnGroup]".to_string(),
        other => format!("[{other}]"),
    }
}

fn form_flags(node: roxmltree::Node<'_, '_>) -> String {
    let mut flags = Vec::new();
    if form_child_text(node, "Visible").as_deref() == Some("false") {
        flags.push("visible:false");
    }
    if form_child_text(node, "Enabled").as_deref() == Some("false") {
        flags.push("enabled:false");
    }
    if form_child_text(node, "ReadOnly").as_deref() == Some("true") {
        flags.push("ro");
    }
    if flags.is_empty() {
        String::new()
    } else {
        format!(" [{}]", flags.join(","))
    }
}

fn form_events_str(node: roxmltree::Node<'_, '_>) -> String {
    let Some(events) = form_child(node, "Events") else {
        return String::new();
    };
    let events = form_children(events, "Event")
        .into_iter()
        .map(|event| {
            let name = event.attribute("name").unwrap_or("");
            let call_type = event.attribute("callType").unwrap_or("");
            if call_type.is_empty() {
                name.to_string()
            } else {
                format!("{name}[{call_type}]")
            }
        })
        .collect::<Vec<_>>();
    if events.is_empty() {
        String::new()
    } else {
        format!(" {{{}}}", events.join(", "))
    }
}

fn form_binding(node: roxmltree::Node<'_, '_>) -> String {
    if let Some(data_path) = form_child_text(node, "DataPath") {
        return format!(" -> {data_path}");
    }
    let Some(command_name) = form_child_text(node, "CommandName") else {
        return String::new();
    };
    if let Some(name) = command_name.strip_prefix("Form.StandardCommand.") {
        format!(" -> {name} [std]")
    } else if let Some(name) = command_name.strip_prefix("Form.Command.") {
        format!(" -> {name} [cmd]")
    } else {
        format!(" -> {command_name}")
    }
}

fn form_title_differs(node: roxmltree::Node<'_, '_>, name: &str) -> Option<String> {
    let title = form_child(node, "Title").map(form_ml_text)?;
    if title.is_empty() || title.replace(' ', "").to_lowercase() == name.to_lowercase() {
        None
    } else {
        Some(title)
    }
}

fn form_count_significant_children(child_items: roxmltree::Node<'_, '_>) -> usize {
    child_items
        .children()
        .filter(|child| {
            child.is_element() && !form_skip_elements().contains(&child.tag_name().name())
        })
        .count()
}

fn form_attribute_lines(attrs: roxmltree::Node<'_, '_>) -> Vec<String> {
    form_children(attrs, "Attribute")
        .into_iter()
        .map(|attr| {
            let name = attr.attribute("name").unwrap_or("");
            let type_str = form_child(attr, "Type")
                .map(form_format_type)
                .unwrap_or_default();
            let is_main = form_child_text(attr, "MainAttribute").as_deref() == Some("true");
            let prefix = if is_main { "*" } else { " " };
            let main_suffix = if is_main { " (main)" } else { "" };
            let mut dyn_table = String::new();
            if type_str == "DynamicList" {
                if let Some(settings) = form_child(attr, "Settings") {
                    if let Some(main_table) = form_child_text(settings, "MainTable") {
                        dyn_table = format!(" -> {main_table}");
                    }
                }
            }
            let mut col_str = String::new();
            if matches!(type_str.as_str(), "ValueTable" | "ValueTree") {
                if let Some(columns) = form_child(attr, "Columns") {
                    let cols = form_children(columns, "Column")
                        .into_iter()
                        .map(|column| {
                            let column_name = column.attribute("name").unwrap_or("");
                            let column_type = form_child(column, "Type")
                                .map(form_format_type)
                                .unwrap_or_default();
                            if column_type.is_empty() {
                                column_name.to_string()
                            } else {
                                format!("{column_name}: {column_type}")
                            }
                        })
                        .collect::<Vec<_>>();
                    if !cols.is_empty() {
                        col_str = format!(" [{}]", cols.join(", "));
                    }
                }
            }
            if type_str.is_empty() && col_str.is_empty() && dyn_table.is_empty() {
                format!("  {prefix}{name}{main_suffix}")
            } else {
                format!("  {prefix}{name}: {type_str}{col_str}{dyn_table}{main_suffix}")
            }
        })
        .collect()
}

fn form_parameter_lines(params: roxmltree::Node<'_, '_>) -> Vec<String> {
    form_children(params, "Parameter")
        .into_iter()
        .map(|param| {
            let name = param.attribute("name").unwrap_or("");
            let type_str = form_child(param, "Type")
                .map(form_format_type)
                .unwrap_or_default();
            let key_suffix = if form_child_text(param, "KeyParameter").as_deref() == Some("true") {
                " (key)"
            } else {
                ""
            };
            if type_str.is_empty() {
                format!("  {name}{key_suffix}")
            } else {
                format!("  {name}: {type_str}{key_suffix}")
            }
        })
        .collect()
}

fn form_command_lines(commands: roxmltree::Node<'_, '_>) -> Vec<String> {
    form_children(commands, "Command")
        .into_iter()
        .map(|command| {
            let name = command.attribute("name").unwrap_or("");
            let shortcut = form_child_text(command, "Shortcut")
                .map(|value| format!(" [{value}]"))
                .unwrap_or_default();
            let actions = form_children(command, "Action");
            let action = if actions.len() > 1 {
                let parts = actions
                    .into_iter()
                    .map(|action| {
                        let text = action.text().unwrap_or("");
                        let call_type = action.attribute("callType").unwrap_or("");
                        if call_type.is_empty() {
                            text.to_string()
                        } else {
                            format!("{text}[{call_type}]")
                        }
                    })
                    .collect::<Vec<_>>();
                format!(" -> {}", parts.join(", "))
            } else if actions.len() == 1 {
                let action_node = actions[0];
                let text = action_node.text().unwrap_or("");
                let call_type = action_node.attribute("callType").unwrap_or("");
                if call_type.is_empty() {
                    format!(" -> {text}")
                } else {
                    format!(" -> {text}[{call_type}]")
                }
            } else {
                String::new()
            };
            format!("  {name}{action}{shortcut}")
        })
        .collect()
}

fn form_format_type(type_node: roxmltree::Node<'_, '_>) -> String {
    if let Some(type_set) = form_child_text(type_node, "TypeSet") {
        return type_set
            .strip_prefix("cfg:")
            .unwrap_or(&type_set)
            .to_string();
    }
    let mut parts = Vec::new();
    for type_item in form_children(type_node, "Type") {
        let raw = type_item.text().unwrap_or("");
        let part = match raw {
            "xs:string" => {
                let length = form_child(type_node, "StringQualifiers")
                    .and_then(|node| form_child_text(node, "Length"))
                    .unwrap_or_else(|| "0".to_string());
                if length != "0" {
                    format!("string({length})")
                } else {
                    "string".to_string()
                }
            }
            "xs:decimal" => {
                if let Some(qualifiers) = form_child(type_node, "NumberQualifiers") {
                    let digits =
                        form_child_text(qualifiers, "Digits").unwrap_or_else(|| "0".to_string());
                    let fraction = form_child_text(qualifiers, "FractionDigits")
                        .unwrap_or_else(|| "0".to_string());
                    format!("decimal({digits},{fraction})")
                } else {
                    "decimal".to_string()
                }
            }
            "xs:boolean" => "boolean".to_string(),
            "xs:dateTime" => match form_child(type_node, "DateQualifiers")
                .and_then(|node| form_child_text(node, "DateFractions"))
                .as_deref()
            {
                Some("Date") => "date".to_string(),
                Some("Time") => "time".to_string(),
                _ => "dateTime".to_string(),
            },
            "xs:binary" => "binary".to_string(),
            "v8:ValueTable" => "ValueTable".to_string(),
            "v8:ValueTree" => "ValueTree".to_string(),
            "v8:ValueListType" => "ValueList".to_string(),
            "v8:TypeDescription" => "TypeDescription".to_string(),
            "v8:Universal" => "Universal".to_string(),
            "v8:FixedArray" => "FixedArray".to_string(),
            "v8:FixedStructure" => "FixedStructure".to_string(),
            "v8ui:FormattedString" => "FormattedString".to_string(),
            "v8ui:Picture" => "Picture".to_string(),
            "v8ui:Color" => "Color".to_string(),
            "v8ui:Font" => "Font".to_string(),
            other if other.starts_with("cfg:") => other[4..].to_string(),
            other if other.starts_with("dcsset:") => other.replacen("dcsset:", "DCS.", 1),
            other if other.starts_with("dcssch:") => other.replacen("dcssch:", "DCS.", 1),
            other if other.starts_with("dcscor:") => other.replacen("dcscor:", "DCS.", 1),
            other => {
                if let Some((prefix, suffix)) = other.split_once(':') {
                    if prefix.starts_with('d')
                        && prefix[1..]
                            .chars()
                            .all(|ch| ch.is_ascii_digit() || ch == 'p')
                    {
                        suffix.to_string()
                    } else {
                        other.to_string()
                    }
                } else {
                    other.to_string()
                }
            }
        };
        parts.push(part);
    }
    parts.join(" | ")
}

impl MetaValidationReporter {
    fn new(max_errors: usize, detailed: bool) -> Self {
        Self {
            errors: 0,
            warnings: 0,
            ok_count: 0,
            stopped: false,
            max_errors,
            detailed,
            lines: vec![String::new()],
            md_type: "(unknown)".to_string(),
            obj_name: "(unknown)".to_string(),
        }
    }

    fn ok(&mut self, message: impl Into<String>) {
        self.ok_count += 1;
        if self.detailed {
            self.lines.push(format!("[OK]    {}", message.into()));
        }
    }

    fn error(&mut self, message: impl Into<String>) {
        self.errors += 1;
        self.lines.push(format!("[ERROR] {}", message.into()));
        if self.errors >= self.max_errors {
            self.stopped = true;
        }
    }

    fn warn(&mut self, message: impl Into<String>) {
        self.warnings += 1;
        self.lines.push(format!("[WARN]  {}", message.into()));
    }

    fn finalize(mut self) -> (bool, String, Vec<String>) {
        let checks = self.ok_count + self.errors + self.warnings;
        let ok = self.errors == 0;
        if ok && self.warnings == 0 && !self.detailed {
            return (
                true,
                format!(
                    "=== Validation OK: {}.{} ({checks} checks) ===",
                    self.md_type, self.obj_name
                ),
                Vec::new(),
            );
        }
        self.lines.insert(
            0,
            format!("=== Validation: {}.{} ===", self.md_type, self.obj_name),
        );
        self.lines.push(String::new());
        self.lines.push(format!(
            "=== Result: {} errors, {} warnings ({checks} checks) ===",
            self.errors, self.warnings
        ));
        let errors = self
            .lines
            .iter()
            .filter(|line| line.starts_with("[ERROR]"))
            .cloned()
            .collect::<Vec<_>>();
        (ok, self.lines.join("\n"), errors)
    }
}

fn validate_meta(args: &Map<String, Value>, context: &WorkspaceContext) -> AdapterOutcome {
    const MD_NS: &str = "http://v8.1c.ru/8.3/MDClasses";

    let result = (|| -> Result<MetaValidationRun, String> {
        let raw_path = required_path(
            args,
            &["objectPath", "ObjectPath", "path", "Path"],
            "ObjectPath",
        )?;
        let raw_path_text = raw_path.to_string_lossy();
        if raw_path_text.contains('|') {
            return Err(
                "[ERROR] Batch validation is not implemented in native meta.validate yet"
                    .to_string(),
            );
        }
        let object_path = resolve_meta_info_path(absolutize(raw_path, &context.cwd))?;
        let resolved_path = object_path
            .canonicalize()
            .unwrap_or_else(|_| object_path.clone());
        let config_dir = meta_validate_config_dir(&resolved_path);
        let out_file_label = string_arg(args, &["outFile", "OutFile"]).map(ToOwned::to_owned);
        let out_file = out_file_label
            .as_ref()
            .map(|path| absolutize(PathBuf::from(path), &context.cwd));
        let detailed = bool_arg(args, &["detailed", "Detailed"]);
        let max_errors = int_arg(args, &["maxErrors", "MaxErrors"])
            .and_then(|value| usize::try_from(value).ok())
            .filter(|value| *value > 0)
            .unwrap_or(30);

        let text = read_utf8_sig(&resolved_path)?;
        let doc = match Document::parse(text.trim_start_matches('\u{feff}')) {
            Ok(doc) => doc,
            Err(err) => {
                let mut report = MetaValidationReporter::new(max_errors, detailed);
                report.md_type = "(parse failed)".to_string();
                report.obj_name.clear();
                report.error(format!("1. XML parse failed: {err}"));
                return meta_validate_finish(report, out_file, out_file_label, resolved_path);
            }
        };

        let root = doc.root_element();
        let mut report = MetaValidationReporter::new(max_errors, detailed);
        let mut check1_ok = true;

        if root.tag_name().name() != "MetaDataObject" {
            report.error(format!(
                "1. Root element is '{}', expected 'MetaDataObject'",
                root.tag_name().name()
            ));
            return meta_validate_finish(report, out_file, out_file_label, resolved_path);
        }

        let root_ns = root.tag_name().namespace().unwrap_or("");
        if root_ns != MD_NS {
            report.error(format!(
                "1. Root namespace is '{root_ns}', expected '{MD_NS}'"
            ));
            check1_ok = false;
        }

        let version = root.attribute("version").unwrap_or("");
        if version.is_empty() {
            report.warn("1. Missing version attribute on MetaDataObject");
        } else if !matches!(version, "2.17" | "2.20") {
            report.warn(format!(
                "1. Unusual version '{version}' (expected 2.17 or 2.20)"
            ));
        }

        let child_elements = root
            .children()
            .filter(|child| child.is_element() && child.tag_name().namespace() == Some(MD_NS))
            .collect::<Vec<_>>();
        if child_elements.is_empty() {
            report.error("1. No metadata type element found inside MetaDataObject");
            return meta_validate_finish(report, out_file, out_file_label, resolved_path);
        }
        if child_elements.len() > 1 {
            let names = child_elements
                .iter()
                .map(|child| format!("'{}'", child.tag_name().name()))
                .collect::<Vec<_>>();
            report.error(format!(
                "1. Multiple type elements found: [{}]",
                names.join(", ")
            ));
            check1_ok = false;
        }

        let type_node = child_elements[0];
        let md_type = type_node.tag_name().name();
        report.md_type = md_type.to_string();
        if !meta_validate_valid_types().contains(&md_type) {
            report.error(format!("1. Unrecognized metadata type: {md_type}"));
            return meta_validate_finish(report, out_file, out_file_label, resolved_path);
        }

        let type_uuid = type_node.attribute("uuid").unwrap_or("");
        if type_uuid.is_empty() {
            report.error(format!("1. Missing uuid on <{md_type}> element"));
            check1_ok = false;
        } else if !is_guid(type_uuid) {
            report.error(format!("1. Invalid uuid '{type_uuid}' on <{md_type}>"));
            check1_ok = false;
        }

        let props_node = meta_info_child(type_node, "Properties");
        let name_node = props_node.and_then(|props| meta_info_child(props, "Name"));
        let obj_name = name_node
            .map(meta_info_inner_text)
            .filter(|value| !value.is_empty())
            .unwrap_or_else(|| "(unknown)".to_string());
        report.obj_name = obj_name.clone();

        if check1_ok {
            report.ok(format!(
                "1. Root structure: MetaDataObject/{md_type}, version {version}"
            ));
        }
        if report.stopped {
            return meta_validate_finish(report, out_file, out_file_label, resolved_path);
        }

        meta_validate_check_internal_info(&mut report, md_type, type_node, &obj_name);
        if report.stopped {
            return meta_validate_finish(report, out_file, out_file_label, resolved_path);
        }
        meta_validate_check_properties(&mut report, props_node, name_node, &obj_name);
        if report.stopped {
            return meta_validate_finish(report, out_file, out_file_label, resolved_path);
        }
        meta_validate_check_property_values(&mut report, props_node);
        if report.stopped {
            return meta_validate_finish(report, out_file, out_file_label, resolved_path);
        }
        meta_validate_check_standard_attributes(&mut report, md_type, props_node);
        if report.stopped {
            return meta_validate_finish(report, out_file, out_file_label, resolved_path);
        }

        let child_obj_node = meta_info_child(type_node, "ChildObjects");
        meta_validate_check_child_objects(&mut report, md_type, child_obj_node);
        if report.stopped {
            return meta_validate_finish(report, out_file, out_file_label, resolved_path);
        }
        meta_validate_check_child_elements(&mut report, child_obj_node);
        if report.stopped {
            return meta_validate_finish(report, out_file, out_file_label, resolved_path);
        }
        meta_validate_check_reserved_attr_names(&mut report, child_obj_node);
        if report.stopped {
            return meta_validate_finish(report, out_file, out_file_label, resolved_path);
        }
        meta_validate_check_uniqueness(&mut report, child_obj_node);
        if report.stopped {
            return meta_validate_finish(report, out_file, out_file_label, resolved_path);
        }
        meta_validate_check_tabular_sections(&mut report, child_obj_node);
        if report.stopped {
            return meta_validate_finish(report, out_file, out_file_label, resolved_path);
        }
        meta_validate_check_cross_properties(
            &mut report,
            md_type,
            props_node,
            child_obj_node,
            config_dir.as_deref(),
            &obj_name,
        );
        if report.stopped {
            return meta_validate_finish(report, out_file, out_file_label, resolved_path);
        }
        meta_validate_check_services(&mut report, md_type, child_obj_node);
        if report.stopped {
            return meta_validate_finish(report, out_file, out_file_label, resolved_path);
        }
        meta_validate_check_forbidden_properties(&mut report, md_type, props_node);
        if report.stopped {
            return meta_validate_finish(report, out_file, out_file_label, resolved_path);
        }
        meta_validate_check_method_reference(
            &mut report,
            md_type,
            props_node,
            config_dir.as_deref(),
        );
        if report.stopped {
            return meta_validate_finish(report, out_file, out_file_label, resolved_path);
        }
        meta_validate_check_document_journal_columns(&mut report, md_type, child_obj_node);

        meta_validate_finish(report, out_file, out_file_label, resolved_path)
    })();

    match result {
        Ok(run) => {
            let mut artifacts = vec![run.artifact.display().to_string()];
            if let Some(out_file) = &run.out_file {
                artifacts.push(out_file.display().to_string());
            }
            AdapterOutcome {
                ok: run.ok,
                summary: if run.ok {
                    "unica.meta.validate completed with native metadata validator".to_string()
                } else {
                    "unica.meta.validate failed in native metadata validator".to_string()
                },
                changes: Vec::new(),
                warnings: Vec::new(),
                errors: run.errors,
                artifacts,
                stdout: Some(run.stdout),
                stderr: Some(String::new()),
                command: None,
            }
        }
        Err(error) => AdapterOutcome {
            ok: false,
            summary: "unica.meta.validate failed in native metadata validator".to_string(),
            changes: Vec::new(),
            warnings: Vec::new(),
            errors: vec![error.clone()],
            artifacts: Vec::new(),
            stdout: Some(format!("{error}\n")),
            stderr: Some(String::new()),
            command: None,
        },
    }
}

fn meta_validate_finish(
    report: MetaValidationReporter,
    out_file: Option<PathBuf>,
    out_file_label: Option<String>,
    artifact: PathBuf,
) -> Result<MetaValidationRun, String> {
    let (ok, result_text, errors) = report.finalize();
    let stdout = if let Some(out_file) = &out_file {
        write_utf8_bom(out_file, &result_text)?;
        let label = out_file_label
            .as_deref()
            .unwrap_or_else(|| out_file.to_str().unwrap_or(""));
        format!("{result_text}\nWritten to: {label}\n")
    } else {
        format!("{result_text}\n")
    };
    Ok(MetaValidationRun {
        ok,
        stdout,
        out_file,
        artifact,
        errors,
    })
}

fn meta_validate_config_dir(resolved_path: &Path) -> Option<PathBuf> {
    let mut probe = resolved_path.parent();
    for _ in 0..4 {
        let Some(dir) = probe else {
            break;
        };
        if dir.join("Configuration.xml").exists() {
            return Some(dir.to_path_buf());
        }
        probe = dir.parent();
    }
    None
}

fn meta_validate_check_internal_info(
    report: &mut MetaValidationReporter,
    md_type: &str,
    type_node: roxmltree::Node<'_, '_>,
    obj_name: &str,
) {
    let internal_info = meta_info_child(type_node, "InternalInfo");
    if meta_validate_types_without_internal_info().contains(&md_type) {
        if let Some(internal_info) = internal_info {
            let gen_types = meta_info_children(internal_info, "GeneratedType");
            if gen_types.is_empty() {
                report.ok(format!(
                    "2. InternalInfo: absent or empty (correct for {md_type})"
                ));
            } else {
                report.warn(format!(
                    "2. InternalInfo: {md_type} should not have GeneratedType entries, found {}",
                    gen_types.len()
                ));
            }
        } else {
            report.ok(format!("2. InternalInfo: absent (correct for {md_type})"));
        }
        return;
    }

    let Some(expected_categories) = meta_validate_generated_categories(md_type) else {
        return;
    };
    let Some(internal_info) = internal_info else {
        report.error(format!(
            "2. InternalInfo: missing (expected {} GeneratedType)",
            expected_categories.len()
        ));
        return;
    };
    let gen_types = meta_info_children(internal_info, "GeneratedType");
    let mut check_ok = true;
    let mut found_categories = Vec::<String>::new();
    for generated_type in &gen_types {
        let name = generated_type.attribute("name").unwrap_or("");
        let category = generated_type.attribute("category").unwrap_or("");
        found_categories.push(category.to_string());
        if !name.is_empty() && obj_name != "(unknown)" && !name.ends_with(&format!(".{obj_name}")) {
            report.error(format!(
                "2. GeneratedType name '{name}' does not end with '.{obj_name}'"
            ));
            check_ok = false;
        }
        if !expected_categories.contains(&category) {
            report.warn(format!(
                "2. Unexpected GeneratedType category '{category}' for {md_type}"
            ));
        }
        if let Some(type_id) = meta_info_child(*generated_type, "TypeId") {
            if !is_guid(&meta_info_inner_text(type_id)) {
                report.error(format!(
                    "2. Invalid TypeId UUID in GeneratedType '{category}'"
                ));
                check_ok = false;
            }
        }
        if let Some(value_id) = meta_info_child(*generated_type, "ValueId") {
            if !is_guid(&meta_info_inner_text(value_id)) {
                report.error(format!(
                    "2. Invalid ValueId UUID in GeneratedType '{category}'"
                ));
                check_ok = false;
            }
        }
    }

    if md_type == "ExchangePlan" {
        if let Some(this_node) = meta_info_child(internal_info, "ThisNode") {
            if !is_guid(&meta_info_inner_text(this_node)) {
                report.error("2. ExchangePlan xr:ThisNode has invalid UUID");
                check_ok = false;
            }
        } else {
            report.warn("2. ExchangePlan missing xr:ThisNode in InternalInfo");
        }
    }

    let missing_categories = expected_categories
        .iter()
        .filter(|category| !found_categories.iter().any(|found| found == **category))
        .copied()
        .collect::<Vec<_>>();
    if !missing_categories.is_empty() {
        report.warn(format!(
            "2. Missing GeneratedType categories: {}",
            missing_categories.join(", ")
        ));
    }
    if check_ok {
        found_categories.sort();
        report.ok(format!(
            "2. InternalInfo: {} GeneratedType ({})",
            gen_types.len(),
            found_categories.join(", ")
        ));
    }
}

fn meta_validate_check_properties(
    report: &mut MetaValidationReporter,
    props_node: Option<roxmltree::Node<'_, '_>>,
    name_node: Option<roxmltree::Node<'_, '_>>,
    obj_name: &str,
) {
    let Some(props_node) = props_node else {
        report.error("3. Properties block missing");
        return;
    };
    let mut check_ok = true;
    if name_node.is_none() || obj_name.is_empty() {
        report.error("3. Properties: Name is missing or empty");
        check_ok = false;
    } else {
        if !is_1c_identifier(obj_name) {
            report.error(format!(
                "3. Properties: Name '{obj_name}' is not a valid 1C identifier"
            ));
            check_ok = false;
        }
        if obj_name.chars().count() > 80 {
            report.warn(format!(
                "3. Properties: Name '{obj_name}' is longer than 80 characters ({})",
                obj_name.chars().count()
            ));
        }
    }
    let syn_present = meta_info_child(props_node, "Synonym")
        .and_then(|node| meta_info_child(node, "item"))
        .and_then(|node| meta_info_child(node, "content"))
        .map(meta_info_inner_text)
        .is_some_and(|value| !value.is_empty());
    if check_ok {
        let syn_info = if syn_present {
            "Synonym present"
        } else {
            "no Synonym"
        };
        report.ok(format!("3. Properties: Name=\"{obj_name}\", {syn_info}"));
    }
}

fn meta_validate_check_property_values(
    report: &mut MetaValidationReporter,
    props_node: Option<roxmltree::Node<'_, '_>>,
) {
    let Some(props_node) = props_node else {
        report.warn("4. No Properties block to check");
        return;
    };
    let mut enum_checked = 0usize;
    let mut check_ok = true;
    for (prop_name, allowed) in meta_validate_property_values() {
        if let Some(value) =
            meta_info_child_text(props_node, prop_name).filter(|value| !value.is_empty())
        {
            if !allowed.contains(&value.as_str()) {
                report.error(format!(
                    "4. Property '{prop_name}' has invalid value '{value}' (allowed: {})",
                    allowed.join(", ")
                ));
                check_ok = false;
            }
            enum_checked += 1;
        }
    }
    if check_ok {
        report.ok(format!(
            "4. Property values: {enum_checked} enum properties checked"
        ));
    }
}

fn meta_validate_check_standard_attributes(
    report: &mut MetaValidationReporter,
    md_type: &str,
    props_node: Option<roxmltree::Node<'_, '_>>,
) {
    if !meta_validate_types_with_std_attrs().contains(&md_type) {
        return;
    }
    let Some(props_node) = props_node else {
        return;
    };
    let Some(std_attr_node) = meta_info_child(props_node, "StandardAttributes") else {
        report.ok(format!(
            "5. StandardAttributes: absent (optional for {md_type})"
        ));
        return;
    };
    let std_attrs = meta_info_children(std_attr_node, "StandardAttribute");
    let expected_std_attrs = meta_validate_standard_attributes(md_type).unwrap_or_default();
    let mut check_ok = true;
    let mut found_names = Vec::<String>::new();
    for standard_attr in &std_attrs {
        let name = standard_attr.attribute("name").unwrap_or("");
        if name.is_empty() {
            report.error("5. StandardAttribute without 'name' attribute");
            check_ok = false;
            continue;
        }
        found_names.push(name.to_string());
        if !expected_std_attrs.contains(&name)
            && !meta_validate_dynamic_standard_attr(md_type, name)
        {
            report.warn(format!(
                "5. Unexpected StandardAttribute '{name}' for {md_type}"
            ));
        }
    }
    let missing_attrs = expected_std_attrs
        .iter()
        .filter(|attr| !found_names.iter().any(|found| found == **attr))
        .copied()
        .collect::<Vec<_>>();
    if !missing_attrs.is_empty() {
        report.warn(format!(
            "5. Missing StandardAttributes: {}",
            missing_attrs.join(", ")
        ));
    }
    if check_ok {
        report.ok(format!(
            "5. StandardAttributes: {} entries",
            std_attrs.len()
        ));
    }
}

fn meta_validate_check_child_objects(
    report: &mut MetaValidationReporter,
    md_type: &str,
    child_obj_node: Option<roxmltree::Node<'_, '_>>,
) {
    let allowed_children = meta_validate_child_rules(md_type).unwrap_or_default();
    if let Some(child_obj_node) = child_obj_node {
        let mut check_ok = true;
        let mut child_counts = BTreeMap::<String, usize>::new();
        for child in child_obj_node.children().filter(|child| child.is_element()) {
            let child_tag = child.tag_name().name();
            if !allowed_children.contains(&child_tag) {
                report.error(format!(
                    "6. ChildObjects: disallowed element '{child_tag}' for {md_type}"
                ));
                check_ok = false;
            }
            *child_counts.entry(child_tag.to_string()).or_default() += 1;
        }
        if check_ok {
            if child_counts.is_empty() {
                report.ok(format!("6. ChildObjects: empty (valid for {md_type})"));
            } else {
                let summary = child_counts
                    .iter()
                    .map(|(name, count)| format!("{name}({count})"))
                    .collect::<Vec<_>>()
                    .join(", ");
                report.ok(format!("6. ChildObjects types: {summary}"));
            }
        }
    } else if allowed_children.is_empty() {
        report.ok(format!("6. ChildObjects: absent (correct for {md_type})"));
    } else {
        report.ok("6. ChildObjects: absent");
    }
}

fn meta_validate_check_child_elements(
    report: &mut MetaValidationReporter,
    child_obj_node: Option<roxmltree::Node<'_, '_>>,
) {
    let Some(child_obj_node) = child_obj_node else {
        return;
    };
    let mut check_ok = true;
    let mut count = 0usize;
    for kind in ["Attribute", "Dimension", "Resource", "EnumValue", "Column"] {
        let require_type = !matches!(kind, "EnumValue" | "Column");
        for element in meta_info_children(child_obj_node, kind) {
            if !meta_validate_check_child_element(report, element, kind, require_type) {
                check_ok = false;
            }
            count += 1;
            if report.stopped {
                break;
            }
        }
    }
    if check_ok && count > 0 {
        report.ok(format!(
            "7. Child elements: {count} items checked (UUID, Name, Type)"
        ));
    } else if count == 0 {
        report.ok("7. Child elements: none to check");
    }
}

fn meta_validate_check_child_element(
    report: &mut MetaValidationReporter,
    node: roxmltree::Node<'_, '_>,
    kind: &str,
    require_type: bool,
) -> bool {
    let uuid = node.attribute("uuid").unwrap_or("");
    if uuid.is_empty() {
        report.error(format!("7. {kind} missing uuid"));
        return false;
    }
    if !is_guid(uuid) {
        report.error(format!("7. {kind} has invalid uuid '{uuid}'"));
        return false;
    }
    let Some(props) = meta_info_child(node, "Properties") else {
        report.error(format!("7. {kind} (uuid={uuid}) missing Properties"));
        return false;
    };
    let name = meta_info_child_text(props, "Name").unwrap_or_default();
    if name.is_empty() {
        report.error(format!("7. {kind} (uuid={uuid}) missing or empty Name"));
        return false;
    }
    if !is_1c_identifier(&name) {
        report.error(format!("7. {kind} '{name}' has invalid identifier"));
        return false;
    }
    if require_type {
        let Some(type_el) = meta_info_child(props, "Type") else {
            report.error(format!("7. {kind} '{name}' missing Type block"));
            return false;
        };
        if meta_info_children(type_el, "Type").is_empty()
            && meta_info_children(type_el, "TypeSet").is_empty()
        {
            report.error(format!(
                "7. {kind} '{name}' Type block has no v8:Type or v8:TypeSet"
            ));
            return false;
        }
    }
    true
}

fn meta_validate_check_reserved_attr_names(
    report: &mut MetaValidationReporter,
    child_obj_node: Option<roxmltree::Node<'_, '_>>,
) {
    let Some(child_obj_node) = child_obj_node else {
        return;
    };
    let mut check_ok = true;
    for attr_node in meta_info_children(child_obj_node, "Attribute") {
        if let Some(name) = meta_info_child(attr_node, "Properties")
            .and_then(|props| meta_info_child_text(props, "Name"))
            .filter(|value| meta_validate_reserved_attr_names().contains(&value.as_str()))
        {
            report.warn(format!(
                "7b. Attribute '{name}' conflicts with a standard attribute name"
            ));
            check_ok = false;
        }
    }
    if check_ok {
        report.ok("7b. Reserved attribute names: no conflicts");
    }
}

fn meta_validate_check_uniqueness(
    report: &mut MetaValidationReporter,
    child_obj_node: Option<roxmltree::Node<'_, '_>>,
) {
    let Some(child_obj_node) = child_obj_node else {
        return;
    };
    let mut check_ok = true;
    for kind in [
        "Attribute",
        "TabularSection",
        "Dimension",
        "Resource",
        "EnumValue",
        "Column",
        "URLTemplate",
        "Operation",
    ] {
        if !meta_validate_names_unique(report, meta_info_children(child_obj_node, kind), kind) {
            check_ok = false;
        }
    }
    if check_ok {
        report.ok("8. Name uniqueness: all names unique");
    }
}

fn meta_validate_names_unique(
    report: &mut MetaValidationReporter,
    nodes: Vec<roxmltree::Node<'_, '_>>,
    kind: &str,
) -> bool {
    let mut names = HashSet::<String>::new();
    let mut ok = true;
    for node in nodes {
        let Some(name) = meta_info_child(node, "Properties")
            .and_then(|props| meta_info_child_text(props, "Name"))
            .filter(|value| !value.is_empty())
        else {
            continue;
        };
        if !names.insert(name.clone()) {
            report.error(format!("8. Duplicate {kind} name: '{name}'"));
            ok = false;
        }
    }
    ok
}

fn meta_validate_check_tabular_sections(
    report: &mut MetaValidationReporter,
    child_obj_node: Option<roxmltree::Node<'_, '_>>,
) {
    let Some(child_obj_node) = child_obj_node else {
        return;
    };
    let sections = meta_info_children(child_obj_node, "TabularSection");
    if sections.is_empty() {
        report.ok("9. TabularSections: none present");
        return;
    }
    let mut check_ok = true;
    for (index, section) in sections.iter().enumerate() {
        let count = index + 1;
        let uuid = section.attribute("uuid").unwrap_or("");
        if uuid.is_empty() || !is_guid(uuid) {
            report.error(format!(
                "9. TabularSection #{count}: invalid or missing uuid"
            ));
            check_ok = false;
        }
        let props = meta_info_child(*section, "Properties");
        let section_name = props
            .and_then(|node| meta_info_child_text(node, "Name"))
            .filter(|value| !value.is_empty())
            .unwrap_or_else(|| "(unnamed)".to_string());
        if section_name == "(unnamed)" {
            report.error(format!("9. TabularSection #{count}: missing or empty Name"));
            check_ok = false;
        }
        if let Some(internal_info) = meta_info_child(*section, "InternalInfo") {
            let generated = meta_info_children(internal_info, "GeneratedType");
            if generated.len() < 2 {
                report.warn(format!(
                    "9. TabularSection '{section_name}': expected 2 GeneratedType, found {}",
                    generated.len()
                ));
            }
        }
        if let Some(ts_child_obj) = meta_info_child(*section, "ChildObjects") {
            let mut names = HashSet::<String>::new();
            for attr in meta_info_children(ts_child_obj, "Attribute") {
                if !meta_validate_check_child_element(
                    report,
                    attr,
                    &format!("TabularSection '{section_name}'.Attribute"),
                    true,
                ) {
                    check_ok = false;
                }
                if let Some(name) = meta_info_child(attr, "Properties")
                    .and_then(|node| meta_info_child_text(node, "Name"))
                    .filter(|value| !value.is_empty())
                {
                    if !names.insert(name.clone()) {
                        report.error(format!(
                            "9. Duplicate attribute '{name}' in TabularSection '{section_name}'"
                        ));
                        check_ok = false;
                    }
                }
            }
            if let Some(props) = props {
                if let Some(std_attr) = meta_info_child(props, "StandardAttributes") {
                    let has_line_number = meta_info_children(std_attr, "StandardAttribute")
                        .iter()
                        .any(|attr| attr.attribute("name") == Some("LineNumber"));
                    if !has_line_number {
                        report.warn(format!(
                            "9. TabularSection '{section_name}': missing LineNumber StandardAttribute"
                        ));
                    }
                }
            }
        }
    }
    if check_ok {
        report.ok(format!(
            "9. TabularSections: {} sections, structure valid",
            sections.len()
        ));
    }
}

fn meta_validate_check_cross_properties(
    report: &mut MetaValidationReporter,
    md_type: &str,
    props_node: Option<roxmltree::Node<'_, '_>>,
    child_obj_node: Option<roxmltree::Node<'_, '_>>,
    config_dir: Option<&Path>,
    obj_name: &str,
) {
    let Some(props_node) = props_node else {
        return;
    };
    let mut check_ok = true;
    let mut issues = 0usize;
    if meta_info_child_text(props_node, "Hierarchical").as_deref() == Some("false") {
        if let Some(hierarchy_type) =
            meta_info_child_text(props_node, "HierarchyType").filter(|value| !value.is_empty())
        {
            report.warn(format!(
                "10. HierarchyType='{hierarchy_type}' but Hierarchical=false"
            ));
            issues += 1;
        }
    }
    if md_type == "CommonModule" {
        let any_enabled = [
            "Server",
            "ClientManagedApplication",
            "ClientOrdinaryApplication",
            "ExternalConnection",
            "ServerCall",
            "Global",
        ]
        .iter()
        .any(|name| meta_info_child_text(props_node, name).as_deref() == Some("true"));
        if !any_enabled {
            report.warn("10. CommonModule: no execution context enabled");
            issues += 1;
        }
    }
    if md_type == "EventSubscription" {
        if meta_info_child_text(props_node, "Handler").is_none_or(|value| value.trim().is_empty()) {
            report.error("10. EventSubscription: empty Handler");
            check_ok = false;
            issues += 1;
        }
        let has_source = meta_info_child(props_node, "Source")
            .map(|node| !meta_info_children(node, "Type").is_empty())
            .unwrap_or(false);
        if !has_source {
            report.warn("10. EventSubscription: no Source types specified");
            issues += 1;
        }
    }
    if md_type == "ScheduledJob"
        && meta_info_child_text(props_node, "MethodName")
            .is_none_or(|value| value.trim().is_empty())
    {
        report.error("10. ScheduledJob: empty MethodName");
        check_ok = false;
        issues += 1;
    }
    for (type_name, property, message) in [
        (
            "AccountingRegister",
            "ChartOfAccounts",
            "10. AccountingRegister: empty ChartOfAccounts",
        ),
        (
            "CalculationRegister",
            "ChartOfCalculationTypes",
            "10. CalculationRegister: empty ChartOfCalculationTypes",
        ),
    ] {
        if md_type == type_name
            && meta_info_child_text(props_node, property)
                .is_none_or(|value| value.trim().is_empty())
        {
            report.error(message);
            check_ok = false;
            issues += 1;
        }
    }
    if md_type == "BusinessProcess"
        && meta_info_child_text(props_node, "Task").is_none_or(|value| value.trim().is_empty())
    {
        report.warn("10. BusinessProcess: empty Task reference");
        issues += 1;
    }
    if md_type == "CalculationRegister"
        && meta_info_child_text(props_node, "ActionPeriod").as_deref() == Some("true")
        && meta_info_child_text(props_node, "Schedule").is_none_or(|value| value.trim().is_empty())
    {
        report.warn(
            "10. CalculationRegister: ActionPeriod=true but Schedule is empty — platform requires a schedule register",
        );
        issues += 1;
    }
    if md_type == "DocumentJournal" {
        let has_registered = meta_info_child(props_node, "RegisteredDocuments")
            .map(|node| !meta_info_children(node, "Type").is_empty())
            .unwrap_or(false);
        if !has_registered {
            report.warn("10. DocumentJournal: no RegisteredDocuments specified");
            issues += 1;
        }
    }
    if md_type == "ChartOfAccounts" {
        let max_ext_dim = meta_info_child_text(props_node, "MaxExtDimensionCount")
            .and_then(|value| value.parse::<i64>().ok())
            .unwrap_or(0);
        if max_ext_dim > 0
            && meta_info_child_text(props_node, "ExtDimensionTypes")
                .is_none_or(|value| value.trim().is_empty())
        {
            report
                .warn("10. ChartOfAccounts: MaxExtDimensionCount>0 but ExtDimensionTypes is empty");
            issues += 1;
        }
    }
    if matches!(
        md_type,
        "AccumulationRegister"
            | "AccountingRegister"
            | "CalculationRegister"
            | "InformationRegister"
    ) {
        if let Some(child_obj_node) = child_obj_node {
            let count = meta_info_children(child_obj_node, "Dimension").len()
                + meta_info_children(child_obj_node, "Resource").len()
                + meta_info_children(child_obj_node, "Attribute").len();
            if count == 0 {
                report.warn(format!(
                    "10. {md_type}: no Dimensions, Resources, or Attributes — platform will reject"
                ));
                issues += 1;
            }
        }
    }
    meta_validate_check_document_register_records(
        report,
        md_type,
        props_node,
        config_dir,
        &mut issues,
    );
    meta_validate_check_register_registrar(
        report,
        md_type,
        props_node,
        config_dir,
        obj_name,
        &mut issues,
    );
    if check_ok && issues == 0 {
        report.ok("10. Cross-property consistency");
    }
}

fn meta_validate_check_document_register_records(
    report: &mut MetaValidationReporter,
    md_type: &str,
    props_node: roxmltree::Node<'_, '_>,
    config_dir: Option<&Path>,
    issues: &mut usize,
) {
    if md_type != "Document" {
        return;
    }
    let Some(config_dir) = config_dir else {
        return;
    };
    let Some(register_records) = meta_info_child(props_node, "RegisterRecords") else {
        return;
    };
    for item in meta_info_children(register_records, "Item") {
        let ref_value = meta_info_inner_text(item).trim().to_string();
        let Some((ref_type, ref_name)) = ref_value.split_once('.') else {
            continue;
        };
        let ref_dir = match ref_type {
            "AccumulationRegister" => "AccumulationRegisters",
            "InformationRegister" => "InformationRegisters",
            "AccountingRegister" => "AccountingRegisters",
            "CalculationRegister" => "CalculationRegisters",
            _ => continue,
        };
        let ref_path = config_dir.join(ref_dir).join(ref_name);
        let ref_xml = config_dir.join(ref_dir).join(format!("{ref_name}.xml"));
        if !ref_path.exists() && !ref_xml.exists() {
            report.warn(format!(
                "10. Document.RegisterRecords references '{ref_value}' but object not found in config"
            ));
            *issues += 1;
        }
    }
}

fn meta_validate_check_register_registrar(
    report: &mut MetaValidationReporter,
    md_type: &str,
    props_node: roxmltree::Node<'_, '_>,
    config_dir: Option<&Path>,
    obj_name: &str,
    issues: &mut usize,
) {
    if !matches!(
        md_type,
        "AccumulationRegister"
            | "AccountingRegister"
            | "CalculationRegister"
            | "InformationRegister"
    ) || obj_name == "(unknown)"
    {
        return;
    }
    if md_type == "InformationRegister"
        && meta_info_child_text(props_node, "WriteMode").as_deref() != Some("RecorderSubordinate")
    {
        return;
    }
    let Some(config_dir) = config_dir else {
        return;
    };
    let docs_dir = config_dir.join("Documents");
    let reg_ref = format!("{md_type}.{obj_name}");
    let mut has_registrar = false;
    if docs_dir.is_dir() {
        if let Ok(entries) = fs::read_dir(&docs_dir) {
            for entry in entries.filter_map(Result::ok) {
                let path = entry.path();
                if path.extension().and_then(|ext| ext.to_str()) != Some("xml") || !path.is_file() {
                    continue;
                }
                if read_utf8_sig(&path)
                    .map(|content| content.contains(&reg_ref))
                    .unwrap_or(false)
                {
                    has_registrar = true;
                    break;
                }
            }
        }
    }
    if !has_registrar {
        report.warn(format!(
            "10. {md_type}: no registrar document found (none references '{reg_ref}' in RegisterRecords)"
        ));
        *issues += 1;
    }
}

fn meta_validate_check_services(
    report: &mut MetaValidationReporter,
    md_type: &str,
    child_obj_node: Option<roxmltree::Node<'_, '_>>,
) {
    let Some(child_obj_node) = child_obj_node else {
        return;
    };
    if md_type == "HTTPService" {
        let templates = meta_info_children(child_obj_node, "URLTemplate");
        let mut check_ok = true;
        let mut method_count = 0usize;
        for template in &templates {
            let props = meta_info_child(*template, "Properties");
            let name = props
                .and_then(|node| meta_info_child_text(node, "Name"))
                .unwrap_or_else(|| "(unnamed)".to_string());
            if props
                .and_then(|node| meta_info_child_text(node, "Template"))
                .is_none_or(|value| value.trim().is_empty())
            {
                report.error(format!(
                    "11. HTTPService URLTemplate '{name}': empty Template"
                ));
                check_ok = false;
            }
            if let Some(child_objects) = meta_info_child(*template, "ChildObjects") {
                for method in meta_info_children(child_objects, "Method") {
                    method_count += 1;
                    let props = meta_info_child(method, "Properties");
                    let http_method =
                        props.and_then(|node| meta_info_child_text(node, "HTTPMethod"));
                    if let Some(http_method) = http_method.filter(|value| !value.is_empty()) {
                        if !meta_validate_valid_http_methods().contains(&http_method.as_str()) {
                            report.error(format!(
                                "11. HTTPService URLTemplate '{name}': invalid HTTPMethod '{http_method}'"
                            ));
                            check_ok = false;
                        }
                    } else {
                        report.error(format!(
                            "11. HTTPService URLTemplate '{name}': Method missing HTTPMethod"
                        ));
                        check_ok = false;
                    }
                }
            }
        }
        if check_ok {
            report.ok(format!(
                "11. HTTPService: {} URLTemplate(s), {method_count} method(s)",
                templates.len()
            ));
        }
    } else if md_type == "WebService" {
        let operations = meta_info_children(child_obj_node, "Operation");
        let mut check_ok = true;
        let mut param_count = 0usize;
        for operation in &operations {
            let props = meta_info_child(*operation, "Properties");
            let name = props
                .and_then(|node| meta_info_child_text(node, "Name"))
                .unwrap_or_else(|| "(unnamed)".to_string());
            if props
                .and_then(|node| meta_info_child_text(node, "XDTOReturningValueType"))
                .is_none_or(|value| value.trim().is_empty())
            {
                report.warn(format!(
                    "11. WebService Operation '{name}': no XDTOReturningValueType"
                ));
            }
            if let Some(child_objects) = meta_info_child(*operation, "ChildObjects") {
                for param in meta_info_children(child_objects, "Parameter") {
                    param_count += 1;
                    let direction = meta_info_child(param, "Properties")
                        .and_then(|node| meta_info_child_text(node, "TransferDirection"));
                    if let Some(direction) = direction.filter(|value| !value.is_empty()) {
                        if !["In", "Out", "InOut"].contains(&direction.as_str()) {
                            report.error(format!(
                                "11. WebService Operation '{name}': Parameter has invalid TransferDirection '{direction}'"
                            ));
                            check_ok = false;
                        }
                    }
                }
            }
        }
        if check_ok {
            report.ok(format!(
                "11. WebService: {} operation(s), {param_count} parameter(s)",
                operations.len()
            ));
        }
    }
}

fn meta_validate_check_forbidden_properties(
    report: &mut MetaValidationReporter,
    md_type: &str,
    props_node: Option<roxmltree::Node<'_, '_>>,
) {
    let Some(props_node) = props_node else {
        return;
    };
    let Some(forbidden) = meta_validate_forbidden_properties(md_type) else {
        return;
    };
    let mut check_ok = true;
    for property in forbidden {
        if meta_info_child(props_node, property).is_some() {
            report.error(format!(
                "12. Forbidden property '{property}' present in {md_type} (will fail on LoadConfigFromFiles)"
            ));
            check_ok = false;
        }
    }
    if check_ok {
        report.ok("12. Forbidden properties: none found");
    }
}

fn meta_validate_check_method_reference(
    report: &mut MetaValidationReporter,
    md_type: &str,
    props_node: Option<roxmltree::Node<'_, '_>>,
    config_dir: Option<&Path>,
) {
    if !matches!(md_type, "EventSubscription" | "ScheduledJob") {
        return;
    }
    let (Some(props_node), Some(config_dir)) = (props_node, config_dir) else {
        return;
    };
    let (property, method_ref) = if md_type == "EventSubscription" {
        ("Handler", meta_info_child_text(props_node, "Handler"))
    } else {
        ("MethodName", meta_info_child_text(props_node, "MethodName"))
    };
    let Some(method_ref) = method_ref.filter(|value| !value.is_empty()) else {
        return;
    };
    let parts = method_ref.split('.').collect::<Vec<_>>();
    let parsed = if parts.len() == 3 && parts[0] == "CommonModule" {
        Some((parts[1], parts[2]))
    } else if parts.len() == 2 {
        Some((parts[0], parts[1]))
    } else {
        None
    };
    let Some((module_name, proc_name)) = parsed else {
        report.error(format!(
            "13. {md_type}.{property} = '{method_ref}': expected format 'CommonModule.ModuleName.ProcedureName'"
        ));
        return;
    };
    let module_xml = config_dir
        .join("CommonModules")
        .join(format!("{module_name}.xml"));
    if !module_xml.exists() {
        report.error(format!(
            "13. {md_type}.{property}: CommonModule '{module_name}' not found (expected {})",
            module_xml.display()
        ));
        return;
    }
    let bsl_path = config_dir
        .join("CommonModules")
        .join(module_name)
        .join("Ext")
        .join("Module.bsl");
    if bsl_path.exists() {
        if let Ok(content) = read_utf8_sig(&bsl_path) {
            if !meta_validate_bsl_has_export(&content, proc_name) {
                report.warn(format!(
                    "13. {md_type}.{property}: procedure '{proc_name}' not found as exported in CommonModule '{module_name}'"
                ));
                return;
            }
        }
    } else {
        report.warn(format!(
            "13. {md_type}.{property}: BSL file not found ({}), cannot verify procedure",
            bsl_path.display()
        ));
        return;
    }
    report.ok(format!("13. Method reference: {property} = '{method_ref}'"));
}

fn meta_validate_check_document_journal_columns(
    report: &mut MetaValidationReporter,
    md_type: &str,
    child_obj_node: Option<roxmltree::Node<'_, '_>>,
) {
    if md_type != "DocumentJournal" {
        return;
    }
    let Some(child_obj_node) = child_obj_node else {
        return;
    };
    let columns = meta_info_children(child_obj_node, "Column");
    let mut check_ok = true;
    let mut empty_ref_count = 0usize;
    for column in &columns {
        let props = meta_info_child(*column, "Properties");
        let name = props
            .and_then(|node| meta_info_child_text(node, "Name"))
            .unwrap_or_else(|| "(unnamed)".to_string());
        let has_items = props
            .and_then(|node| meta_info_child(node, "References"))
            .map(|node| !meta_info_children(node, "Item").is_empty())
            .unwrap_or(false);
        if !has_items {
            report.error(format!(
                "14. DocumentJournal Column '{name}': empty References (will fail on LoadConfigFromFiles)"
            ));
            check_ok = false;
            empty_ref_count += 1;
        }
    }
    if check_ok && !columns.is_empty() {
        report.ok(format!(
            "14. DocumentJournal Columns: {} column(s), all have References",
            columns.len()
        ));
    } else if columns.is_empty() && empty_ref_count == 0 {
        report.ok("14. DocumentJournal Columns: none");
    }
}

fn meta_validate_bsl_has_export(content: &str, proc_name: &str) -> bool {
    content.lines().any(|line| {
        let trimmed = line.trim_start();
        let starts = ["Procedure", "Function", "Процедура", "Функция"]
            .iter()
            .any(|prefix| trimmed.starts_with(prefix));
        starts
            && trimmed.contains(proc_name)
            && (trimmed.contains(" Export") || trimmed.contains(" Экспорт"))
    })
}

fn is_guid(value: &str) -> bool {
    let bytes = value.as_bytes();
    value.len() == 36
        && [8, 13, 18, 23].iter().all(|index| bytes[*index] == b'-')
        && value
            .chars()
            .enumerate()
            .all(|(index, ch)| [8, 13, 18, 23].contains(&index) || ch.is_ascii_hexdigit())
}

