fn append_metadata_child_text(xml_text: &str, local_name: &str, item_name: &str) -> Option<String> {
    for close in ["</ChildObjects>", "</md:ChildObjects>"] {
        if let Some(index) = xml_text.find(close) {
            let prefix = if close.starts_with("</md:") {
                "md:"
            } else {
                ""
            };
            let line_start = xml_text[..index].rfind('\n').map_or(0, |pos| pos + 1);
            let closing_indent = &xml_text[line_start..index];
            let line = format!(
                "\t<{prefix}{local_name}>{item_name}</{prefix}{local_name}>\n{closing_indent}"
            );
            let mut result = String::with_capacity(xml_text.len() + line.len());
            result.push_str(&xml_text[..index]);
            result.push_str(&line);
            result.push_str(&xml_text[index..]);
            return Some(result);
        }
    }

    for empty in ["<ChildObjects/>", "<md:ChildObjects/>"] {
        if let Some(index) = xml_text.find(empty) {
            let prefix = if empty.starts_with("<md:") { "md:" } else { "" };
            let replacement = format!(
                "<{prefix}ChildObjects>\n\t\t\t<{prefix}{local_name}>{item_name}</{prefix}{local_name}>\n\t\t</{prefix}ChildObjects>"
            );
            let mut result = String::with_capacity(xml_text.len() + replacement.len());
            result.push_str(&xml_text[..index]);
            result.push_str(&replacement);
            result.push_str(&xml_text[index + empty.len()..]);
            return Some(result);
        }
    }

    None
}

fn update_main_data_composition_schema_text(
    xml_text: &str,
    template_name: &str,
    set_main_skd: bool,
) -> (String, bool, String) {
    let Some((object_type, object_start)) = ["ExternalReport", "Report"]
        .iter()
        .find_map(|name| find_open_tag(xml_text, name).map(|index| (*name, index)))
    else {
        return (xml_text.to_string(), false, String::new());
    };
    let object_name = first_tag_text_after(xml_text, "Name", object_start);
    let Some((open_start, content_start, close_start, close_end, open_tag, close_tag)) =
        find_element_bounds(xml_text, "MainDataCompositionSchema", object_start)
    else {
        return (xml_text.to_string(), false, String::new());
    };
    let content = xml_text[content_start..close_start].trim();
    if !content.is_empty() && !set_main_skd {
        return (xml_text.to_string(), false, String::new());
    }
    let value = format!("{object_type}.{object_name}.Template.{template_name}");
    let replacement = format!("{open_tag}{value}{close_tag}");
    let mut result = String::with_capacity(xml_text.len() + value.len());
    result.push_str(&xml_text[..open_start]);
    result.push_str(&replacement);
    result.push_str(&xml_text[close_end..]);
    (result, true, value)
}

fn find_open_tag(xml_text: &str, local_name: &str) -> Option<usize> {
    [format!("<{local_name}"), format!("<md:{local_name}")]
        .iter()
        .filter_map(|needle| xml_text.find(needle))
        .min()
}

fn first_tag_text_after(xml_text: &str, local_name: &str, start: usize) -> String {
    let Some((_, content_start, close_start, _, _, _)) =
        find_element_bounds(xml_text, local_name, start)
    else {
        return String::new();
    };
    xml_text[content_start..close_start].trim().to_string()
}

fn find_element_bounds(
    xml_text: &str,
    local_name: &str,
    start: usize,
) -> Option<(usize, usize, usize, usize, String, String)> {
    for tag in [local_name.to_string(), format!("md:{local_name}")] {
        let open_needle = format!("<{tag}");
        let Some(open_rel) = xml_text[start..].find(&open_needle) else {
            continue;
        };
        let open_start = start + open_rel;
        let Some(open_end_rel) = xml_text[open_start..].find('>') else {
            continue;
        };
        let content_start = open_start + open_end_rel + 1;
        let close_tag = format!("</{tag}>");
        let Some(close_rel) = xml_text[content_start..].find(&close_tag) else {
            continue;
        };
        let close_start = content_start + close_rel;
        let close_end = close_start + close_tag.len();
        let open_tag = xml_text[open_start..content_start].to_string();
        return Some((
            open_start,
            content_start,
            close_start,
            close_end,
            open_tag,
            close_tag,
        ));
    }
    None
}

fn remove_template_child_text_lxml(xml_text: &str, template_name: &str) -> String {
    remove_metadata_child_text_lxml(xml_text, "Template", template_name)
}

fn remove_metadata_child_text_lxml(xml_text: &str, local_name: &str, item_name: &str) -> String {
    let plain = format!("<{local_name}>{item_name}</{local_name}>");
    let prefixed = format!("<md:{local_name}>{item_name}</md:{local_name}>");
    for (open, target) in [
        ("<ChildObjects>", plain.as_str()),
        ("<md:ChildObjects>", prefixed.as_str()),
    ] {
        let Some(open_idx) = xml_text.find(open) else {
            continue;
        };
        let after_open = open_idx + open.len();
        if !xml_text[after_open..].starts_with('\n') {
            continue;
        }
        let child_indent_start = after_open + 1;
        let child_start = child_indent_start
            + xml_text[child_indent_start..]
                .chars()
                .take_while(|ch| *ch == '\t' || *ch == ' ')
                .map(char::len_utf8)
                .sum::<usize>();
        if !xml_text[child_start..].starts_with(target) {
            continue;
        }
        let after_child = child_start + target.len();
        if !xml_text[after_child..].starts_with('\n') {
            continue;
        }
        let next_line_start = after_child + 1;
        let next_content_start = next_line_start
            + xml_text[next_line_start..]
                .chars()
                .take_while(|ch| *ch == '\t' || *ch == ' ')
                .map(char::len_utf8)
                .sum::<usize>();
        let mut result = String::with_capacity(xml_text.len());
        result.push_str(&xml_text[..after_open]);
        result.push_str(&xml_text[next_content_start..]);
        return result;
    }
    remove_metadata_child_text(xml_text, local_name, item_name)
}

fn remove_metadata_child_text(xml_text: &str, local_name: &str, item_name: &str) -> String {
    remove_metadata_child_text_with_flag(xml_text, local_name, item_name).0
}

fn remove_metadata_child_text_with_flag(
    xml_text: &str,
    local_name: &str,
    item_name: &str,
) -> (String, bool) {
    let plain = format!("<{local_name}>{item_name}</{local_name}>");
    let prefixed = format!("<md:{local_name}>{item_name}</md:{local_name}>");
    let mut removed = false;
    let mut result = String::with_capacity(xml_text.len());
    for line in xml_text.split_inclusive('\n') {
        let trimmed = line.trim();
        if !removed && (trimmed == plain || trimmed == prefixed) {
            removed = true;
            continue;
        }
        result.push_str(line);
    }
    if removed {
        (result, true)
    } else if let Some(index) = xml_text.find(&plain) {
        let mut result = xml_text.to_string();
        result.replace_range(index..index + plain.len(), "");
        (result, true)
    } else if let Some(index) = xml_text.find(&prefixed) {
        let mut result = xml_text.to_string();
        result.replace_range(index..index + prefixed.len(), "");
        (result, true)
    } else {
        (xml_text.to_string(), false)
    }
}

struct MetaRemoveReference {
    file: String,
    pattern: String,
}

fn read_utf8_sig(path: &Path) -> Result<String, String> {
    let mut text = fs::read_to_string(path)
        .map_err(|err| format!("failed to read {}: {err}", path.display()))?;
    if text.starts_with('\u{feff}') {
        text.remove(0);
    }
    Ok(text)
}

fn ensure_trailing_newline(mut text: String) -> String {
    if !text.ends_with('\n') {
        text.push('\n');
    }
    text
}

fn metadata_object_registered(config_xml: &Path, obj_type: &str, obj_name: &str) -> bool {
    let Ok(text) = read_utf8_sig(config_xml) else {
        return false;
    };
    text.contains(&format!("<{obj_type}>{obj_name}</{obj_type}>"))
        || text.contains(&format!("<md:{obj_type}>{obj_name}</md:{obj_type}>"))
}

fn count_files_recursive(path: &Path) -> usize {
    let Ok(entries) = fs::read_dir(path) else {
        return 0;
    };
    entries
        .filter_map(Result::ok)
        .map(|entry| {
            let path = entry.path();
            if path.is_dir() {
                count_files_recursive(&path)
            } else if path.is_file() {
                1
            } else {
                0
            }
        })
        .sum()
}

#[allow(clippy::too_many_arguments)]
fn meta_remove_references(
    config_dir: &Path,
    obj_type: &str,
    obj_name: &str,
    type_plural: &str,
    obj_xml: &Path,
    obj_dir: &Path,
    has_xml: bool,
    has_dir: bool,
) -> Vec<MetaRemoveReference> {
    let patterns = meta_remove_search_patterns(obj_type, obj_name, type_plural);
    let mut references = Vec::new();
    let mut already_found = HashSet::new();
    let files = metadata_files_recursive(config_dir);

    for file in files.iter().filter(|file| {
        matches!(
            file.extension().and_then(|ext| ext.to_str()).map(str::to_ascii_lowercase),
            Some(ext) if ext == "xml" || ext == "bsl"
        )
    }) {
        if meta_remove_should_skip_file(file, config_dir, obj_xml, obj_dir, has_xml, has_dir) {
            continue;
        }
        let Ok(content) = read_utf8_sig(file) else {
            continue;
        };
        let rel = relative_display(file, config_dir);
        for pattern in &patterns {
            if content.contains(pattern) {
                already_found.insert(rel.clone());
                references.push(MetaRemoveReference {
                    file: rel,
                    pattern: pattern.clone(),
                });
                break;
            }
        }
    }

    let type_name_ref = format!("{obj_type}.{obj_name}");
    for file in files.iter().filter(|file| {
        file.extension()
            .and_then(|ext| ext.to_str())
            .is_some_and(|ext| ext.eq_ignore_ascii_case("xml"))
    }) {
        if meta_remove_should_skip_file(file, config_dir, obj_xml, obj_dir, has_xml, has_dir) {
            continue;
        }
        let rel = relative_display(file, config_dir);
        if already_found.contains(&rel) {
            continue;
        }
        let Ok(content) = read_utf8_sig(file) else {
            continue;
        };
        if content.contains(&type_name_ref) {
            references.push(MetaRemoveReference {
                file: rel,
                pattern: type_name_ref.clone(),
            });
        }
    }

    references
}

fn metadata_files_recursive(root: &Path) -> Vec<PathBuf> {
    let mut result = Vec::new();
    let Ok(entries) = fs::read_dir(root) else {
        return result;
    };
    let mut entries = entries.filter_map(Result::ok).collect::<Vec<_>>();
    entries.sort_by_key(|entry| entry.file_name());
    for entry in entries {
        let path = entry.path();
        if path.is_dir() {
            result.extend(metadata_files_recursive(&path));
        } else if path.is_file() {
            result.push(path);
        }
    }
    result
}

fn meta_remove_should_skip_file(
    file: &Path,
    config_dir: &Path,
    obj_xml: &Path,
    obj_dir: &Path,
    has_xml: bool,
    has_dir: bool,
) -> bool {
    if has_xml && file == obj_xml {
        return true;
    }
    if has_dir && (file == obj_dir || file.starts_with(obj_dir)) {
        return true;
    }
    let rel = relative_display(file, config_dir);
    rel == "Configuration.xml" || rel == "ConfigDumpInfo.xml" || rel.starts_with("Subsystems")
}

fn relative_display(path: &Path, base: &Path) -> String {
    path.strip_prefix(base)
        .unwrap_or(path)
        .to_string_lossy()
        .replace('\\', "/")
}

fn meta_remove_search_patterns(obj_type: &str, obj_name: &str, type_plural: &str) -> Vec<String> {
    let mut patterns = Vec::new();
    if let Some(ref_names) = meta_remove_type_ref_names(obj_type) {
        patterns.extend(ref_names.iter().map(|name| format!("{name}.{obj_name}")));
    }
    if let Some(manager) = meta_remove_ru_manager(obj_type) {
        patterns.push(format!("{manager}.{obj_name}"));
    }
    patterns.push(format!("{type_plural}.{obj_name}"));
    if obj_type == "CommonModule" {
        patterns.push(format!("{obj_name}."));
        patterns.push(format!("<Handler>{obj_name}."));
        patterns.push(format!("<MethodName>{obj_name}."));
    }
    patterns
}

fn remove_object_from_subsystems(
    dir: &Path,
    obj_type: &str,
    obj_name: &str,
    dry_run: bool,
    stdout: &mut String,
    subsystems_cleaned: &mut usize,
    changes: &mut Vec<String>,
) -> Result<(), String> {
    let mut entries = fs::read_dir(dir)
        .map_err(|err| format!("failed to read {}: {err}", dir.display()))?
        .filter_map(Result::ok)
        .collect::<Vec<_>>();
    entries.sort_by_key(|entry| entry.file_name());

    for entry in entries {
        let path = entry.path();
        if !path.is_file()
            || !path
                .extension()
                .and_then(|ext| ext.to_str())
                .is_some_and(|ext| ext.eq_ignore_ascii_case("xml"))
        {
            continue;
        }

        let mut text = match read_utf8_sig(&path) {
            Ok(text) => text,
            Err(_) => continue,
        };
        let subsystem_name =
            first_tag_text_in_xml(&text, "Name").unwrap_or_else(|| file_stem_string(&path));
        let mut modified = false;
        loop {
            let (next_text, removed) = remove_metadata_child_text_with_flag(
                &text,
                "Item",
                &format!("{obj_type}.{obj_name}"),
            );
            if !removed {
                break;
            }
            stdout.push_str(&format!(
                "[OK]    Removed from subsystem '{subsystem_name}'\n"
            ));
            *subsystems_cleaned += 1;
            modified = true;
            text = next_text;
        }

        if modified && !dry_run {
            write_utf8_bom(&path, &ensure_trailing_newline(text))?;
            changes.push(format!("updated {}", path.display()));
        }

        let child_dir = path
            .parent()
            .unwrap_or(dir)
            .join(file_stem_string(&path))
            .join("Subsystems");
        if child_dir.is_dir() {
            remove_object_from_subsystems(
                &child_dir,
                obj_type,
                obj_name,
                dry_run,
                stdout,
                subsystems_cleaned,
                changes,
            )?;
        }
    }

    Ok(())
}

fn first_tag_text_in_xml(xml_text: &str, local_name: &str) -> Option<String> {
    for tag in [local_name.to_string(), format!("md:{local_name}")] {
        let open = format!("<{tag}>");
        let close = format!("</{tag}>");
        let Some(start) = xml_text.find(&open) else {
            continue;
        };
        let content_start = start + open.len();
        let Some(close_rel) = xml_text[content_start..].find(&close) else {
            continue;
        };
        let text = xml_text[content_start..content_start + close_rel].trim();
        if !text.is_empty() {
            return Some(text.to_string());
        }
    }
    None
}

fn file_stem_string(path: &Path) -> String {
    path.file_stem()
        .and_then(|name| name.to_str())
        .unwrap_or_default()
        .to_string()
}

